def my_atoi(s):
    s = s.strip()
    if not s: return 0
    sign = -1 if s[0]=='-' else 1
    if s[0] in ('+','-'): s = s[1:]
    result = 0
    for c in s:
        if not c.isdigit(): break
        result = result*10 + int(c)
    return max(-2**31, min(sign*result, 2**31-1))

