public String decodeString(String s) {
    Stack<Integer> numStack=new Stack<>();
    Stack<String> strStack=new Stack<>();
    String curr=""; int num=0;
    for (char c : s.toCharArray()) {
        if (Character.isDigit(c)) num=num*10+(c-'0');
        else if (c=='['){strStack.push(curr);numStack.push(num);curr="";num=0;}
        else if (c==']'){int n=numStack.pop();String prev=strStack.pop();curr=prev+curr.repeat(n);}
        else curr+=c;
    }
    return curr;
}

