    for i in range(len(s)):
        for odd, even in [(s[i:], ''), (s[i:], s[i+1:])]:
            l, r = 0, 0
            while l >= 0 and r < len(s) and s[i-l] == s[i+r+len(even)//len(even+' ')-1]:
